'use client'

import Image from "next/image";
import logo from "@/assets/placeholderLogo.png"; // usa @ se tiver alias configurado
import { useRouter } from "next/navigation";
import { usePageTransition } from "@/context/PageTransitionContext";

export default function Navbar() {
  const router = useRouter()
  const controls = usePageTransition()

  const handleNavigate = async (path: string) => {
    // dispara animação de saída
    await controls.start({
      transform: "translateX(-100%)",
      transition: { duration: 3, ease: 'easeInOut' },
    })

    // navega após animação
    router.push(path)

    // reseta animação para entrada
    controls.start({
      transform: "translateX(100%)",
      transition: { duration: 3, ease: 'easeOut' },
    })
  }
  
  const menuItens = [
    { name: "Home", path: "/", id: 1 },
    { name: "A Exitos", path: "/a-exitos", id: 2 },
    { name: "Serviços", path: "/servicos", id: 3 },
    { name: "Clientes", path: "/clientes", id: 4 },
    { name: "Projetos", path: "/projetos", id: 5 },
  ];

  return (
    <nav className="navbar flex items-center justify-between px-6 py-3 bg-white shadow">
      <div className="navbar__logo flex items-center">
        <a onClick={() => handleNavigate(menuItens[0].path)}>
          <Image
            src={logo}
            alt="Logo"
            width={120}
            height={40}
            priority
            className="cursor-pointer"
          />
        </a>
      </div>

      <ul className="navbar__menu flex gap-6">
        {menuItens.map((item) => (
          <li key={item.id}>
            <a
              onClick={() => handleNavigate(item.path)}
              className="navbar__menu-link"
            >
              {item.name}
            </a>
          </li>
        ))}
      </ul>
    </nav>
  );
}
